import React from "react";
import { Box, Container, Divider, Stack, Typography } from "@mui/material";

export default function AboutSection() {
  return (
    <Box sx={{ py: { xs: 6, md: 9 } }}>
      <Container>
        <Stack spacing={2} sx={{ maxWidth: 900 }}>
          <Typography variant="h4">About Us</Typography>
          <Typography color="text.secondary">
            This is an Exotic Car Rental & Track Experience web application. It lets users browse a curated
            fleet of high-performance cars, select a track configuration, and reserve a date—powered by a
            simple REST API.
          </Typography>
        </Stack>
      </Container>
    </Box>
  );
}
